2	export type Cell = [number, number];
3	
4	const key = ([x, y]: Cell): string => `${x},${y}`;
5	
6	const NEIGHBOR_OFFSETS: Cell[] = [
7	  [-1, -1], [0, -1], [1, -1],
8	  [-1,  0],          [1,  0],
9	  [-1,  1], [0,  1], [1,  1],
10	];
11	
12	const countLiveNeighbors = ([x, y]: Cell, liveSet: Set<string>): number =>
13	  NEIGHBOR_OFFSETS.filter(([dx, dy]) => liveSet.has(key([x + dx, y + dy]))).length;
14	
15	const survives = (neighbors: number): boolean => neighbors === 2 || neighbors === 3;
16	
17	export function nextGeneration(liveCells: Cell[]): Cell[] {
18	  const liveSet = new Set(liveCells.map(key));
19	  const candidates = new Map<string, Cell>();
20	  for (const [x, y] of liveCells) {
21	    candidates.set(key([x, y]), [x, y]);
22	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
23	      const neighbor: Cell = [x + dx, y + dy];
24	      candidates.set(key(neighbor), neighbor);
25	    }
26	  }
27	  const result: Cell[] = [];
28	  for (const cell of candidates.values()) {
29	    const isLive = liveSet.has(key(cell));
30	    const n = countLiveNeighbors(cell, liveSet);
31	    if (isLive && survives(n)) result.push(cell);
32	    else if (!isLive && n === 3) result.push(cell);
33	  }
34	  return result;
35	}
